const orderId = $fromAI('order_id', 'ID de la orden');
const validationCode = $fromAI('validation_code', 'Código validador de la orden');
const domain = $env.APP_DOMAIN;

if (!orderId || !validationCode) {
  return { error: 'Se necesita orderId y validationCode para generar el link.' };
}

const link = `${domain}/order/${orderId}?token=${validationCode}`;
return { 
  trackingLink: link, 
  message: `🔍 Puedes seguir tu pedido en tiempo real aquí: ${link}` 
};
